<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { ElMessage } from 'element-plus'
import { adminApi, type Brand, type Category } from '@/api/services'
const categories = ref<Category[]>([]); const brands = ref<Brand[]>([]); const tab = ref('category'); const dialog = ref(false); const kind = ref<'category' | 'brand'>('category'); const editingId = ref<number>(); const saving = ref(false)
const categoryForm = reactive({ name: '', parentId: undefined as number | undefined, sortOrder: 0, status: 1 }); const brandForm = reactive({ name: '', logoUrl: '', sortOrder: 0, status: 1 })
const load = async () => { [categories.value, brands.value] = await Promise.all([adminApi.categories(), adminApi.brands()]) }
const openCategory = (item?: Category) => { kind.value = 'category'; editingId.value = item?.id; Object.assign(categoryForm, { name: item?.name || '', parentId: item?.parentId, sortOrder: item?.sortOrder || 0, status: item?.status ?? 1 }); dialog.value = true }
const openBrand = (item?: Brand) => { kind.value = 'brand'; editingId.value = item?.id; Object.assign(brandForm, { name: item?.name || '', logoUrl: item?.logoUrl || '', sortOrder: item?.sortOrder || 0, status: item?.status ?? 1 }); dialog.value = true }
const save = async () => { saving.value = true; try { if (kind.value === 'category') { const payload = { ...categoryForm }; editingId.value ? await adminApi.updateCategory(editingId.value, payload) : await adminApi.createCategory(payload) } else { const payload = { ...brandForm }; editingId.value ? await adminApi.updateBrand(editingId.value, payload) : await adminApi.createBrand(payload) } ElMessage.success('保存成功'); dialog.value = false; await load() } finally { saving.value = false } }
onMounted(load)
</script>
<template><div><div class="admin-page-title"><div><span>CATALOG</span><h1>分类与品牌</h1><p>维护商品发布时使用的分类和品牌基础数据。</p></div><el-button type="primary" @click="tab === 'category' ? openCategory() : openBrand()">新增{{ tab === 'category' ? '分类' : '品牌' }}</el-button></div><section class="admin-card"><el-tabs v-model="tab"><el-tab-pane label="商品分类" name="category"><el-table :data="categories"><el-table-column prop="id" label="ID" width="80" /><el-table-column prop="name" label="分类名称" /><el-table-column label="上级分类"><template #default="scope">{{ categories.find((item) => item.id === scope.row.parentId)?.name || '顶级分类' }}</template></el-table-column><el-table-column prop="sortOrder" label="排序" width="90" /><el-table-column label="状态" width="100"><template #default="scope"><el-tag :type="scope.row.status === 1 ? 'success' : 'info'">{{ scope.row.status === 1 ? '启用' : '停用' }}</el-tag></template></el-table-column><el-table-column label="操作" width="100"><template #default="scope"><el-button text type="primary" @click="openCategory(scope.row)">编辑</el-button></template></el-table-column></el-table></el-tab-pane><el-tab-pane label="商品品牌" name="brand"><el-table :data="brands"><el-table-column prop="id" label="ID" width="80" /><el-table-column label="品牌"><template #default="scope"><div class="brand-cell"><img v-if="scope.row.logoUrl" :src="scope.row.logoUrl" :alt="scope.row.name" /><b>{{ scope.row.name }}</b></div></template></el-table-column><el-table-column prop="logoUrl" label="Logo URL" show-overflow-tooltip /><el-table-column prop="sortOrder" label="排序" width="90" /><el-table-column label="状态" width="100"><template #default="scope"><el-tag :type="scope.row.status === 1 ? 'success' : 'info'">{{ scope.row.status === 1 ? '启用' : '停用' }}</el-tag></template></el-table-column><el-table-column label="操作" width="100"><template #default="scope"><el-button text type="primary" @click="openBrand(scope.row)">编辑</el-button></template></el-table-column></el-table></el-tab-pane></el-tabs></section><el-dialog v-model="dialog" :title="`${editingId ? '编辑' : '新增'}${kind === 'category' ? '分类' : '品牌'}`" width="520px"><el-form v-if="kind === 'category'" :model="categoryForm" label-width="88px"><el-form-item label="分类名称" required><el-input v-model="categoryForm.name" /></el-form-item><el-form-item label="上级分类"><el-select v-model="categoryForm.parentId" clearable placeholder="顶级分类"><el-option v-for="item in categories.filter((entry) => entry.id !== editingId)" :key="item.id" :label="item.name" :value="item.id" /></el-select></el-form-item><el-form-item label="排序"><el-input-number v-model="categoryForm.sortOrder" :min="0" :max="9999" /></el-form-item><el-form-item label="状态"><el-switch v-model="categoryForm.status" :active-value="1" :inactive-value="0" /></el-form-item></el-form><el-form v-else :model="brandForm" label-width="88px"><el-form-item label="品牌名称" required><el-input v-model="brandForm.name" /></el-form-item><el-form-item label="Logo URL"><el-input v-model="brandForm.logoUrl" placeholder="https://..." /></el-form-item><el-form-item label="排序"><el-input-number v-model="brandForm.sortOrder" :min="0" :max="9999" /></el-form-item><el-form-item label="状态"><el-switch v-model="brandForm.status" :active-value="1" :inactive-value="0" /></el-form-item></el-form><template #footer><el-button @click="dialog = false">取消</el-button><el-button type="primary" :loading="saving" :disabled="kind === 'category' ? !categoryForm.name : !brandForm.name" @click="save">保存</el-button></template></el-dialog></div></template>
